mapper.select:
select last_read_seq
from im_room_read_state
where room_id = #{roomId, jdbcType=BINARY}
  and user_id = #{userId, jdbcType=BINARY}

mapper.update:
update im_room_read_state
set last_read_seq = greatest(last_read_seq, #{lastReadSeq}),
    updated_at = current_timestamp
where room_id = #{roomId, jdbcType=BINARY}
  and user_id = #{userId, jdbcType=BINARY}
